import{_ as t,o as e,c as r,a2 as a}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Broker Page Blocks","description":"Broker Page Blocks for FXT Theme","frontmatter":{"title":"Broker Page Blocks","description":"Broker Page Blocks for FXT Theme","weight":60,"extra":{"order":60},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/broker-page-blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/broker-page-blocks"}],["meta",{"property":"og:title","content":"Broker Page Blocks"}],["meta",{"property":"og:description","content":"Broker Page Blocks for FXT Theme"}],["meta",{"name":"twitter:title","content":"Broker Page Blocks"}],["meta",{"name":"twitter:description","content":"Broker Page Blocks for FXT Theme"}]]},"headers":[],"relativePath":"docs/fxt/broker-page-blocks.md","filePath":"docs/fxt/broker-page-blocks.md"}'),n={name:"docs/fxt/broker-page-blocks.md"};function i(s,o,l,c,p,d){return e(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="broker-page-blocks" tabindex="-1">Broker Page Blocks <a class="header-anchor" href="#broker-page-blocks" aria-label="Permalink to &quot;Broker Page Blocks&quot;">​</a></h1><p>FXT theme comes with built-in broker page blocks and components that you can use to easily present broker information on broker review pages.</p><h2 id="using-broker-page-blocks" tabindex="-1">Using Broker Page Blocks <a class="header-anchor" href="#using-broker-page-blocks" aria-label="Permalink to &quot;Using Broker Page Blocks&quot;">​</a></h2><p>Broker page blocks are specifically designed to display broker information and are automatically populated from the broker fields you fill in when creating broker posts.</p><hr><h2 id="available-broker-page-blocks" tabindex="-1">Available Broker Page Blocks <a class="header-anchor" href="#available-broker-page-blocks" aria-label="Permalink to &quot;Available Broker Page Blocks&quot;">​</a></h2><h3 id="properties-block" tabindex="-1">Properties Block <a class="header-anchor" href="#properties-block" aria-label="Permalink to &quot;Properties Block&quot;">​</a></h3><p>The Properties block displays comprehensive broker information in a structured table format.</p><p><strong>Information Displayed</strong>:</p><ul><li><strong>General Info</strong>: Country support, rating, regulations, licenses, established year, headquarters</li><li><strong>Trading Options</strong>: Trading instruments count, trading platforms</li><li><strong>Payment Information</strong>: Minimum deposit, withdrawal processing time, fees</li><li><strong>Trading Conditions</strong>: Minimum trade size, average spread, maximum leverage</li><li><strong>Customer Support</strong>: Support channels, supported languages</li></ul><p><strong>Configuration</strong>: No configuration required - automatically populated from broker fields.</p><p><strong>Usage</strong>: Add the Properties block to any broker page to display all broker information in an organized table.</p><hr><h3 id="pros-cons-block" tabindex="-1">Pros &amp; Cons Block <a class="header-anchor" href="#pros-cons-block" aria-label="Permalink to &quot;Pros &amp; Cons Block&quot;">​</a></h3><p>The Pros &amp; Cons block displays broker advantages and disadvantages in a clear, visual format.</p><p><strong>Information Displayed</strong>:</p><ul><li><strong>Pros</strong>: List of broker advantages with checkmark icons</li><li><strong>Cons</strong>: List of broker disadvantages with appropriate styling</li></ul><p><strong>Configuration</strong>: No configuration required - automatically populated from broker fields.</p><p><strong>Usage</strong>: Add the Pros &amp; Cons block to highlight broker strengths and weaknesses.</p><hr><h3 id="real-account-button-block" tabindex="-1">Real Account Button Block <a class="header-anchor" href="#real-account-button-block" aria-label="Permalink to &quot;Real Account Button Block&quot;">​</a></h3><p>The Real Account Button block creates prominent call-to-action buttons for real trading accounts.</p><p><strong>Features</strong>:</p><ul><li><strong>Button Styling</strong>: Uses theme&#39;s real account button design</li><li><strong>Terms Display</strong>: Includes terms and conditions popover</li><li><strong>External Link Handling</strong>: Properly configured for external broker links</li></ul><p><strong>Configuration</strong>:</p><ul><li><strong>Button URL</strong>: Set the destination URL for the real account link</li><li><strong>Terms Text</strong>: Add terms and conditions text</li><li><strong>Custom Anchor Text</strong>: Override default button text if needed</li></ul><p><strong>Usage</strong>: Add this block to create prominent real account signup buttons.</p><hr><h3 id="country-support-with-buttons-block" tabindex="-1">Country Support with Buttons Block <a class="header-anchor" href="#country-support-with-buttons-block" aria-label="Permalink to &quot;Country Support with Buttons Block&quot;">​</a></h3><p>The Country Support with Buttons block displays broker availability by country with action buttons.</p><p><strong>Features</strong>:</p><ul><li><strong>Geographic Display</strong>: Shows which countries the broker supports</li><li><strong>Action Buttons</strong>: Includes real account and demo account buttons for each supported country</li><li><strong>Visual Indicators</strong>: Clear country support visualization</li></ul><p><strong>Configuration</strong>: No configuration required - automatically populated from broker fields.</p><p><strong>Usage</strong>: Add this block to show broker geographic coverage with action buttons.</p><hr><h2 id="adding-blocks-to-broker-pages" tabindex="-1">Adding Blocks to Broker Pages <a class="header-anchor" href="#adding-blocks-to-broker-pages" aria-label="Permalink to &quot;Adding Blocks to Broker Pages&quot;">​</a></h2><ol><li>Edit a broker page in WordPress</li><li>Click the <strong>+</strong> button to add a new block</li><li>Search for the desired block name in the <strong>FXT Blocks</strong> section</li><li>Click on the block to add it to your page</li></ol><hr><h2 id="block-customization" tabindex="-1">Block Customization <a class="header-anchor" href="#block-customization" aria-label="Permalink to &quot;Block Customization&quot;">​</a></h2><p>Most broker page blocks require no configuration and automatically display information from broker fields. For blocks that do require configuration:</p><ol><li>Select the block in the editor</li><li>Use the block toolbar for quick actions</li><li>Configure block settings in the right sidebar</li><li>Use the block inspector for advanced options</li></ol><hr><h2 id="data-integration" tabindex="-1">Data Integration <a class="header-anchor" href="#data-integration" aria-label="Permalink to &quot;Data Integration&quot;">​</a></h2><h3 id="automatic-population" tabindex="-1">Automatic Population <a class="header-anchor" href="#automatic-population" aria-label="Permalink to &quot;Automatic Population&quot;">​</a></h3><p>Broker page blocks automatically pull data from:</p><ul><li><strong>Basic Information</strong>: Logo, name, type, website, main feature, founded year, headquarters</li><li><strong>Regulations &amp; Licenses</strong>: Regulatory bodies and license information</li><li><strong>Trading Conditions</strong>: Minimum trade size, spreads, leverage</li><li><strong>Trading Instruments</strong>: Available trading instruments and counts</li><li><strong>Payment Options</strong>: Deposit/withdrawal methods and fees</li><li><strong>Customer Support</strong>: Support channels and languages</li><li><strong>Pros &amp; Cons</strong>: Broker advantages and disadvantages</li></ul><h3 id="field-requirements" tabindex="-1">Field Requirements <a class="header-anchor" href="#field-requirements" aria-label="Permalink to &quot;Field Requirements&quot;">​</a></h3><p>To ensure blocks display properly, make sure to fill in all required broker fields when creating broker posts. Empty fields will not display in the blocks.</p><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/page-templates">Page Templates</a></p>',51)])])}const k=t(n,[["render",i]]);export{u as __pageData,k as default};
